import{_ as a,o as r,c as d,a2 as o}from"./chunks/framework.BQ1gajhD.js";const q=JSON.parse('{"title":"景山公园","description":"","frontmatter":{},"headers":[],"relativePath":"landmarks/jingshan/index.md","filePath":"landmarks/jingshan/index.md","lastUpdated":1784720050000}'),n={name:"landmarks/jingshan/index.md"};function e(s,t,h,l,i,g){return r(),d("div",null,[...t[0]||(t[0]=[o('<h1 id="景山公园" tabindex="-1">景山公园 <a class="header-anchor" href="#景山公园" aria-label="Permalink to &quot;景山公园&quot;">​</a></h1><p><img src="https://images.unsplash.com/photo-1736237174975-0be4f327f35d?w=1200&amp;q=80" alt="景山公园俯瞰故宫"></p><blockquote><p>&quot;会当凌绝顶，一览紫禁小。&quot;——站在北京内城制高点，六百年的皇家气象尽收眼底。</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>景山公园位于北京故宫北侧，地处北京内城的几何中心，是元、明、清三代的皇家御苑。公园占地23公顷，园内主峰海拔88.7米，是北京内城的制高点。这里曾是明代&quot;万岁山&quot;、清代&quot;景山&quot;，见证了中国历史上最惊心动魄的一幕——1644年明思宗朱由检在此自缢殉国。</p><p>如今的景山公园，既是市民晨练、赏花的日常去处，也是游客俯瞰紫禁城全景的绝佳观景点。万春亭上的日出日落，五方亭间的四季轮转，让这座有着近千年历史的皇家园林，在当代依然焕发着独特的魅力。无论是摄影爱好者追逐的&quot;京城天际线&quot;，还是历史爱好者凭吊的崇祯殉国处，景山都以其独特的位置与厚重的历史，成为北京旅行不可错过的一站。</p><hr><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th>项目</th><th>内容</th></tr></thead><tbody><tr><td><strong>门票</strong></td><td>旺季2元 / 淡季2元</td></tr><tr><td><strong>旺季时间</strong></td><td>6:00-21:00（4月-10月）</td></tr><tr><td><strong>淡季时间</strong></td><td>6:30-20:00（11月-3月）</td></tr><tr><td><strong>公交</strong></td><td>101、103、109、111、124路景山东街站</td></tr><tr><td><strong>地铁</strong></td><td>closest: 地铁8号线什刹海站</td></tr><tr><td><strong>步行</strong></td><td>故宫神武门（北门）出，向北步行约500米即达</td></tr><tr><td><strong>地址</strong></td><td>北京市西城区景山西街44号</td></tr></tbody></table><hr><h2 id="子景点导览" tabindex="-1">子景点导览 <a class="header-anchor" href="#子景点导览" aria-label="Permalink to &quot;子景点导览&quot;">​</a></h2><div class="landmark-grid"><table tabindex="0"><thead><tr><th>子景点</th><th>特色</th><th>建议游览</th></tr></thead><tbody><tr><td><a href="/beijing-travel-guide/landmarks/jingshan/wanchun-ting.html">万春亭</a></td><td>北京内城最高点，俯瞰故宫全景</td><td>30-45分钟</td></tr><tr><td><a href="/beijing-travel-guide/landmarks/jingshan/chongzhen-xuanguo.html">崇祯殉国处</a></td><td>明思宗自缢老槐树遗址，历史凭吊</td><td>15-20分钟</td></tr><tr><td><a href="/beijing-travel-guide/landmarks/jingshan/wufang-ting.html">五方亭</a></td><td>五座观景亭，对应五行五方</td><td>30-40分钟</td></tr><tr><td><a href="/beijing-travel-guide/landmarks/jingshan/qiwang-lou.html">绮望楼</a></td><td>清代官式建筑代表，景山历史综合</td><td>15-20分钟</td></tr></tbody></table></div><hr><h2 id="推荐游览路线" tabindex="-1">推荐游览路线 <a class="header-anchor" href="#推荐游览路线" aria-label="Permalink to &quot;推荐游览路线&quot;">​</a></h2><h3 id="经典半日路线-约2-5小时" tabindex="-1">经典半日路线（约2.5小时） <a class="header-anchor" href="#经典半日路线-约2-5小时" aria-label="Permalink to &quot;经典半日路线（约2.5小时）&quot;">​</a></h3><p><strong>南门进 → 崇祯殉国处 → 万春亭 → 五方亭 → 西门出</strong></p><ol><li><strong>南门进</strong>：从景山公园南门入园，迎面便是皇家园林的气派格局。</li><li><strong>崇祯殉国处</strong>（东侧）：沿东侧步道前行，参观&quot;明思宗殉国处&quot;石碑与老槐树遗址，感受历史的沉重。</li><li><strong>万春亭</strong>：沿主路登顶，在景山最高点俯瞰故宫全景、北海白塔、钟鼓楼，是全程的高潮。</li><li><strong>五方亭</strong>：从山顶向西，依次游览周赏亭、观妙亭、辑芳亭、富览亭，欣赏五方亭的建筑之美。</li><li><strong>西门出</strong>：从西门离园，可顺路前往北海公园或什刹海继续游览。</li></ol><p><strong>替代路线：东门出</strong></p><p>若想前往北大红楼、中国美术馆一带，可从东门出园，途经绮望楼外观后继续向东。</p><hr><h2 id="京城天际线-拍照点" tabindex="-1">&quot;京城天际线&quot;拍照点 <a class="header-anchor" href="#京城天际线-拍照点" aria-label="Permalink to &quot;&quot;京城天际线&quot;拍照点&quot;">​</a></h2><p>景山万春亭是北京最具标志性的城市天际线拍摄点之一。站在海拔88.7米的制高点，向南可拍摄故宫全景中轴线，向北可远眺钟鼓楼与奥林匹克塔，向西可见北海白塔与国家大剧院，向东则能捕捉到央视大楼（CCTV总部）的现代轮廓。</p><h3 id="最佳机位" tabindex="-1">最佳机位 <a class="header-anchor" href="#最佳机位" aria-label="Permalink to &quot;最佳机位&quot;">​</a></h3><table tabindex="0"><thead><tr><th>方向</th><th>拍摄内容</th><th>最佳时间</th></tr></thead><tbody><tr><td><strong>南</strong></td><td>故宫全景中轴线</td><td>日出后1小时 / 日落前1小时</td></tr><tr><td><strong>北</strong></td><td>钟鼓楼、奥林匹克塔</td><td>傍晚蓝调时刻</td></tr><tr><td><strong>西</strong></td><td>北海白塔、国家大剧院</td><td>日落时分</td></tr><tr><td><strong>东</strong></td><td>央视大楼天际线</td><td>夜间灯光亮起后</td></tr></tbody></table><blockquote><p><strong>摄影提示</strong>：建议携带广角镜头（16-35mm）和三脚架。节假日游客众多，清晨6:30开园时前往可获得最佳机位。</p></blockquote><hr><h2 id="四季景色" tabindex="-1">四季景色 <a class="header-anchor" href="#四季景色" aria-label="Permalink to &quot;四季景色&quot;">​</a></h2><table tabindex="0"><thead><tr><th>季节</th><th>主要景观</th><th>最佳时间</th></tr></thead><tbody><tr><td><strong>春</strong></td><td>牡丹花海、芍药争艳</td><td>4月中旬-5月中旬</td></tr><tr><td><strong>夏</strong></td><td>古树浓荫、荷花初绽</td><td>6月-8月</td></tr><tr><td><strong>秋</strong></td><td>银杏金黄、红叶漫山</td><td>10月中旬-11月上旬</td></tr><tr><td><strong>冬</strong></td><td>雪覆紫禁城、银装素裹</td><td>12月-次年2月</td></tr></tbody></table><h3 id="春季·牡丹" tabindex="-1">春季·牡丹 <a class="header-anchor" href="#春季·牡丹" aria-label="Permalink to &quot;春季·牡丹&quot;">​</a></h3><p><img src="https://images.unsplash.com/photo-1754119431062-b818396bc36a?w=1200&amp;q=80" alt="景山牡丹"></p><p>景山公园是北京最著名的牡丹观赏地之一，每年4月中旬至5月中旬举办&quot;景山牡丹节&quot;，园内种植牡丹、芍药万余株，涵盖姚黄、魏紫、赵粉、豆绿等传统名品。五方亭下的牡丹园，更是花开时节游人如织。</p><h3 id="冬季·雪" tabindex="-1">冬季·雪 <a class="header-anchor" href="#冬季·雪" aria-label="Permalink to &quot;冬季·雪&quot;">​</a></h3><p><img src="https://images.unsplash.com/photo-1773734313426-2bbf04d368d1?w=1200&amp;q=80" alt="雪后景山"></p><p>雪后的景山，是摄影爱好者的天堂。当皑皑白雪覆盖在黄色琉璃瓦上，紫禁城在白雪的映衬下更显庄严壮丽。万春亭上的雪景，是北京冬季最经典的画面之一。</p><hr><h2 id="历史小知识" tabindex="-1">历史小知识 <a class="header-anchor" href="#历史小知识" aria-label="Permalink to &quot;历史小知识&quot;">​</a></h2><ul><li><strong>金代</strong>：此处为金中都的&quot;瑶屿行宫&quot;，是皇家游幸之所。</li><li><strong>元代</strong>：成为元大都的中心，称&quot;青山&quot;。</li><li><strong>明代</strong>：永乐年间修建紫禁城时，将拆除元故宫的渣土堆积于此，形成&quot;万岁山&quot;，又称&quot;镇山&quot;&quot;堆煤山&quot;。</li><li><strong>清代</strong>：顺治年间改名为&quot;景山&quot;，取&quot;仰瞻高山，景行行止&quot;之意。</li><li><strong>民国</strong>：1928年正式开放为公园。</li><li><strong>现代</strong>：现为全国重点文物保护单位，国家AAAA级旅游景区。</li></ul><hr><p><strong>📍 地址</strong>：北京市西城区景山西街44号</p><p><strong>⏱️ 建议游览</strong>：2-3小时</p><p><strong>🔗 周边景点</strong>：故宫博物院 · 北海公园 · 什刹海 · 钟鼓楼</p>',41)])])}const b=a(n,[["render",e]]);export{q as __pageData,b as default};
